import{_ as A,o as B,c as p,C as e,N as a,D as t}from"./chunks/framework.4896357c.js";const d=JSON.parse('{"title":"webgpuDemo（进行中...）","description":"","frontmatter":{"title":"webgpuDemo（进行中...）","outline":"deep","date":"2023-04-23T00:00:00.000Z","tags":["WebGPU","Stu","荒野"]},"headers":[],"relativePath":"posts/webgpu.md"}'),c={name:"posts/webgpu.md"},i=a('<p>管线</p><ul><li>什么是管线呢？</li></ul><p>管线这个说法并不是只存在于gpu的，cpu中的管线指的是执行管道流水线，简称为管线，管线对于cpu的关系就类似于汽车组装线与汽车之间的关心。cpu管线并不是物理意义上提供数据输入输出的管路或通道，它是为了执行指令而归纳出的下一步需要做的事情。</p><p>回到正题，gpu架构和cpu有极大不同，因为两者适用于不同的场合。想象一下，gpu面对3d游戏中成千上万的三角面，若仅仅是逐一单个处理计算，损失的效率是及其惊人的。</p><p>这可以类比汽车工业的发展，在1913年前福特开发出汽车流水线之前，汽车组装只能让一位位工人逐工序完成，年产不过12台，效率极低。在引入流水线概念之后，每位工人只需要不停的做一道工序，所有工序并行进行，效率可提高八倍。</p><p>gpu对图像处理的高效率体现了同样的思路，gpu采用数量众的计算单元和超长额流水线，但每一个部分只有非常简单的控制逻辑（如同摩登时代中一个流水线工人只负责拧一个螺丝）。尽管计算能力不如cpu，但耐不住人多力量大。好比一千道十以内加减法同时给一百个小学生和一个大学生来做，尽管小学生能力小，但这么多小学生同时做耗时肯定是比一个大学生来的快。</p><ul><li>渲染管线 render pipeline</li></ul><p>在渲染流程中，cpu与gpu正如上文一样通力合作渲染图像。在运算过程中，cpu如进货卡车一样不断将要处理的数据丢给gpu，gpu工厂调动计算单元对数据进行简单处理，最后组装出产品---图像。</p><ul><li>应用阶段 application stage</li></ul><p>这是由cpu主要负责的阶段，且完全由开发人员控制。这个阶段，cpu将决定递给gpu什么样的数据（比如渲染目标场景中的灯光，场景的模型，摄像机的位置），有时候还会对这些数据进行处理（比如只递给gpu可以被摄像机看见的元素，其他不可见的元素被剔除）并且告诉gpu这些数据的渲染状态（比如纹理，材质着色器等）</p><ul><li>几何阶段 gemometry stage</li></ul><p>这是一个由gpu主导的阶段，也就是从该阶段开始进入上文所说的流水线。几何阶段将cpu在应用阶段发来的数据进行进一步处理，而这个阶段又可以进一步细分为若干个流水线阶段，可以类比理解为工厂流水线进行一道道工序。</p><img src="https://pic3.zhimg.com/80/v2-a1665bf2063e67a0d924e10c2121600e_720w.webp" data-caption="" data-size="normal" data-rawwidth="891" data-rawheight="394" class="origin_image zh-lightbox-thumb lazy" width="891" data-original="https://pic3.zhimg.com/v2-a1665bf2063e67a0d924e10c2121600e_r.jpg" data-actualsrc="https://pic3.zhimg.com/v2-a1665bf2063e67a0d924e10c2121600e_b.jpg" data-original-token="v2-100feccc9c6777c38a907087446d9627" height="394" data-lazy-status="ok" style=""><p>流程图中展现了几何阶段常见的渲染步骤（不同图像应用接口存在不同，这里以openGL为栗子），其中绿色部分代表开发者可以完全编程控制的部分，黄色部分代表开发者无法完全控制的部分（但可以进行一些配置），紫色部分表示开发者无法控制的阶段（已经由GPU固定实现）。</p><p>下面详细解释这几个细分阶段所做的工作。</p><p>1.放入显存与Draw call</p><p>在应用阶段，cpu从硬盘中将需要的数据放入内存中，经过之前描述的一系列操作后，再打包发给gpu进行进一步处理。虽然从渲染的角度来看，当cpu将数据传递到显存中后，这些数据再内存中的使用就结束了，可以移除了，但对于一些特殊数据仍然可以幸存；比如游戏中的一面墙，不仅需要渲染出来，还需进行物体碰撞的计算，那么cpu在将他的网格丢给gpu后并不会将其马上从内存中移除，因为还需要用它进行网格计算。</p><p>在应用阶段，</p><h2 id="附录" tabindex="-1">附录 <a class="header-anchor" href="#附录" aria-label="Permalink to &quot;附录&quot;">​</a></h2><p>引用链接和资料查询:</p><ul><li><p><a style="cursor:pointer;" href="https://zhuanlan.zhihu.com/p/137780634"> 卷毛狒狒看的渲染管线 </a></p></li><li><p><a style="cursor:pointer;" href="https://blog.csdn.net/hikaliv/article/details/4258715#:~:text=%E6%AF%8F%E5%9D%97CPU%E4%B8%AD%E9%83%BD%E6%9C%89%E2%80%9C%E6%89%A7%E8%A1%8C%E7%AE%A1%E9%81%93%E6%B5%81%E6%B0%B4%E7%BA%BF%E2%80%9D%E7%9A%84%E5%AD%98%E5%9C%A8%EF%BC%88%E4%BB%A5%E4%B8%8B%E7%AE%80%E7%A7%B0%E2%80%9C%E7%AE%A1%E7%BA%BF%E2%80%9D%EF%BC%89%EF%BC%8C%E7%AE%A1%E7%BA%BF%E5%AF%B9%E4%BA%8ECPU%E7%9A%84%E5%85%B3%E7%B3%BB%E5%B0%B1%E7%B1%BB%E4%BC%BC%E6%B1%BD%E8%BD%A6%E7%BB%84%E8%A3%85%E7%BA%BF%E4%B8%8E%E6%B1%BD%E8%BD%A6%E4%B9%8B%E9%97%B4%E7%9A%84%E5%85%B3%E7%B3%BB%E3%80%82.%20CPU%E7%9A%84%E7%AE%A1%E7%BA%BF%E5%B9%B6%E4%B8%8D%E6%98%AF%E7%89%A9%E7%90%86%E6%84%8F%E4%B9%89%E4%B8%8A%E4%BE%9B%E6%95%B0%E6%8D%AE%E8%BE%93%E5%85%A5%E8%BE%93%E5%87%BA%E7%9A%84%E7%9A%84%E7%AE%A1%E8%B7%AF%E6%88%96%E9%80%9A%E9%81%93%EF%BC%8C%E5%AE%83%E6%98%AF%E4%B8%BA%E4%BA%86%E6%89%A7%E8%A1%8C%E6%8C%87%E4%BB%A4%E8%80%8C%E5%BD%92%E7%BA%B3%E5%87%BA%E7%9A%84%E2%80%9C%E4%B8%8B%E4%B8%80%E6%AD%A5%E9%9C%80%E8%A6%81%E5%81%9A%E7%9A%84%E4%BA%8B%E6%83%85%E2%80%9D%E3%80%82.%20%E6%AF%8F%E4%B8%80%E4%B8%AA%E6%8C%87%E4%BB%A4%E7%9A%84%E6%89%A7%E8%A1%8C%E9%83%BD%E5%BF%85%E9%A1%BB%E7%BB%8F%E8%BF%87%E7%9B%B8%E5%90%8C%E7%9A%84%E6%AD%A5%E9%AA%A4%EF%BC%8C%E6%88%91%E4%BB%AC%E6%8A%8A%E8%BF%99%E6%A0%B7%E7%9A%84%E6%AD%A5%E9%AA%A4%E7%A7%B0%E4%BD%9C%E2%80%9C%E7%BA%A7%E2%80%9D%E3%80%82.,%E7%AE%A1%E7%BA%BF%E4%B8%AD%E7%9A%84%E2%80%9C%E7%BA%A7%E2%80%9D%E7%9A%84%E4%BB%BB%E5%8A%A1%E5%8C%85%E6%8B%AC%E5%88%86%E6%94%AF%E4%B8%8B%E4%B8%80%E6%AD%A5%E8%A6%81%E6%89%A7%E8%A1%8C%E7%9A%84%E6%8C%87%E4%BB%A4%E3%80%81%E5%88%86%E6%94%AF%E6%95%B0%E6%8D%AE%E7%9A%84%E8%BF%90%E7%AE%97%E7%BB%93%E6%9E%9C%E3%80%81%E5%88%86%E6%94%AF%E7%BB%93%E6%9E%9C%E7%9A%84%E5%AD%98%E5%82%A8%E4%BD%8D%E7%BD%AE%E3%80%81%E6%89%A7%E8%A1%8C%E8%BF%90%E7%AE%97%E7%AD%89%E7%AD%89%E2%80%A6%E2%80%A6.%20%E6%9C%80%E5%9F%BA%E7%A1%80%E7%9A%84CPU%E7%AE%A1%E7%BA%BF%E5%8F%AF%E4%BB%A5%E8%A2%AB%E5%88%86%E4%B8%BA5%E7%BA%A7%EF%BC%9A.%201%E3%80%81%E5%8F%96%E6%8C%87%E4%BB%A4."> cpu执行管道流水线 </a></p></li></ul>',21);function u(o,l,s,r,C,n){const E=t("webgpudemo");return B(),p("div",null,[e(E),i])}const D=A(c,[["render",u]]);export{d as __pageData,D as default};
